for filename, body_html in pages.items():
    path = Path(filename)
    text = path.read_text(encoding='utf-8')
    body_start = text.index('<div class="legal-body">', text.index('<body>'))
    footer_start = text.rindex('<footer>')
    new_text = text[:body_start] + body_html + text[footer_start:]
    if '.legal-body pre' not in new_text:
        new_text = new_text.replace('.legal-body p{', '.legal-body p{\n  white-space: normal;\n}')
    path.write_text(new_text, encoding='utf-8')
    print(f'Updated {filename}')
